17→suspend inline fun <PAYLOAD, reified EVENT : Any> Dispatcher.dispatchAndAwait(
18→    action: Action<PAYLOAD>
19→): EVENT = coroutineScope {
20→    val deferred = async { awaitEvent<EVENT>() }
21→    dispatch(action)
22→
23→    return@coroutineScope deferred.await()
24→}
