26→suspend inline fun <reified EVENT : Any> Dispatcher.awaitEvent(): EVENT = suspendCancellableCoroutine { continuation ->
27→    val listener = object : GenericEventBusListener<EVENT>(EVENT::class) {
28→        override fun handleEvent(event: EVENT) {
29→            unregister(this)
30→            if (!continuation.isActive) {
31→                AppLog.w(AppLog.T.UTILS, "Listener for ${EVENT::class} invoked after cancellation")
32→                return
33→            }
34→            continuation.resume(event)
35→        }
36→    }
37→    register(listener)
38→
39→    continuation.invokeOnCancellation {
40→        unregister(listener)
41→    }
42→}
43→
44→inline fun <reified EVENT : Any> Dispatcher.observeEvents(): Flow<EVENT> = callbackFlow {
45→    val listener = object : GenericEventBusListener<EVENT>(EVENT::class) {
46→        override fun handleEvent(event: EVENT) {
47→            trySend(event)
48→                .onFailure {
49→                    AppLog.w(AppLog.T.UTILS, "Failure to emit EventBus's event $event as Flow, ${it?.toString()}")
50→                }
51→        }
52→    }
53→    register(listener)
54→
55→    awaitClose {
56→        unregister(listener)
57→    }
58→}
59→
60→abstract class GenericEventBusListener<EVENT : Any>(private val kClass: KClass<EVENT>) {
61→    @Subscribe(threadMode = ThreadMode.MAIN)
62→    @Suppress("unused")
63→    fun onEvent(event: EVENT) {
64→        // Since generic types are suppressed at runtime, this listener will be registered using the type Object
65→        // But using the reified EVENT type, we can compare the class and ignore unwanted events
66→        if (event::class != kClass) return
67→
68→        handleEvent(event)
69→    }
70→
71→    abstract fun handleEvent(event: EVENT)
72→}
