        val trimmedQuery = query.trim()
        if (trimmedQuery == currentQueryText) return

        currentQueryText = trimmedQuery
        latestSearchRequestId += 1
        val requestId = latestSearchRequestId

        // Cancel any in-flight request immediately; its response should never update the UI for the new query.
